// Construye el contexto acumulado: deseo original + todo lo que la IA
// ya le sugirió en ciclos anteriores, para que el siguiente prompt
// SEA una continuación real, no un correo genérico repetido.

const wish = $('Procesar uno por uno').first().json;
const history = $input.all().map(item => item.json);

const historyText = history.length
  ? history.reverse().map(h => `Ciclo ${h.cycle_number}: ${h.action_taken}`).join('\n')
  : 'Este es el primer ciclo de seguimiento (correo de los 7 días).';

const cycleNumber = (wish.followups_sent || 0) + 1;

return [{ json: { ...wish, historyText, cycleNumber } }];

