const planRaw = $input.first().json.choices[0].message.content;
let plan;
try {
  plan = JSON.parse(planRaw.replace(/```json|```/g, '').trim());
} catch(e) {
  plan = { siguiente_paso: 'Revisa tu progreso de esta semana', razonamiento: 'fallback', ciclo_completo: false };
}
const prev = $('Construir contexto acumulado').first().json;
return [{ json: { ...prev, plan } }];

